 1→import { useCallback, useEffect, useState } from 'react';
 2→import { recentCommandDb } from '../utils/database';
 3→
 4→const MAX_RECENT = 10;
 5→
 6→export function useRecentCommands() {
 7→  const [recentIds, setRecentIds] = useState<string[]>([]);
 8→
 9→  useEffect(() => {
10→    let cancelled = false;
11→    recentCommandDb
12→      .getAll(MAX_RECENT)
13→      .then(ids => {
14→        if (!cancelled) setRecentIds(ids);
15→      })
16→      .catch(console.error);
17→    return () => {
18→      cancelled = true;
19→    };
20→  }, []);
21→
22→  const addRecent = useCallback((id: string) => {
23→    setRecentIds(prev => {
24→      const next = [
25→        id,
26→        ...prev.filter(rid => rid !== id),
27→      ].slice(0, MAX_RECENT);
28→      return next;
29→    });
30→    recentCommandDb.add(id).catch(console.error);
31→  }, []);
32→
33→  const clearRecent = useCallback(() => {
34→    setRecentIds([]);
35→    recentCommandDb.clear().catch(console.error);
36→  }, []);
37→
38→  return {
39→    recentIds,
40→    addRecent,
41→    clearRecent,
42→  };
43→}
