 1→import { useCallback, useEffect, useMemo, useState } from 'react';
 2→import { settingsDb } from '../utils/database';
 3→
 4→const DB_KEY = 'favorites';
 5→
 6→function parseIds(raw: string | null): string[] {
 7→  if (!raw) return [];
 8→  try {
 9→    const parsed: unknown = JSON.parse(raw);
10→    if (Array.isArray(parsed) && parsed.every(v => typeof v === 'string')) {
11→      return parsed as string[];
12→    }
13→  } catch {
14→    // invalid
15→  }
16→  return [];
17→}
18→
19→export function useFavorites() {
20→  const [favoriteIds, setFavoriteIds] = useState<string[]>([]);
21→
22→  useEffect(() => {
23→    let cancelled = false;
24→    settingsDb
25→      .get(DB_KEY)
26→      .then(raw => {
27→        if (!cancelled) setFavoriteIds(parseIds(raw));
28→      })
29→      .catch(console.error);
30→    return () => {
31→      cancelled = true;
32→    };
33→  }, []);
34→
35→  const favoriteSet = useMemo(() => new Set(favoriteIds), [favoriteIds]);
36→
37→  const isFavorite = useCallback(
38→    (id: string) => favoriteSet.has(id),
39→    [favoriteSet],
40→  );
41→
42→  const toggleFavorite = useCallback((id: string) => {
43→    setFavoriteIds(prev => {
44→      const next = prev.includes(id)
45→        ? prev.filter(fid => fid !== id)
46→        : [
47→            ...prev,
48→            id,
49→          ];
50→      settingsDb.set(DB_KEY, JSON.stringify(next)).catch(console.error);
51→      return next;
52→    });
53→  }, []);
54→
55→  const moveFavorite = useCallback((id: string, direction: 'up' | 'down') => {
56→    setFavoriteIds(prev => {
57→      const idx = prev.indexOf(id);
58→      if (idx === -1) return prev;
59→      const targetIdx = direction === 'up' ? idx - 1 : idx + 1;
60→      if (targetIdx < 0 || targetIdx >= prev.length) return prev;
61→      const next = [...prev];
62→      next[idx] = prev[targetIdx]!;
63→      next[targetIdx] = prev[idx]!;
64→      settingsDb.set(DB_KEY, JSON.stringify(next)).catch(console.error);
65→      return next;
66→    });
67→  }, []);
68→
69→  return {
70→    favoriteIds,
71→    isFavorite,
72→    toggleFavorite,
73→    moveFavorite,
74→  };
75→}
