 1→import { useCallback, useEffect, useState } from 'react';
 2→import { settingsDb } from '../utils/database';
 3→
 4→type ThemePreference = 'dark' | 'light' | 'system';
 5→type ResolvedTheme = 'dark' | 'light';
 6→
 7→const DB_KEY = 'theme';
 8→
 9→function isThemePreference(value: unknown): value is ThemePreference {
10→  return value === 'dark' || value === 'light' || value === 'system';
11→}
12→
13→function getSystemTheme(): ResolvedTheme {
14→  return window.matchMedia('(prefers-color-scheme: light)').matches
15→    ? 'light'
16→    : 'dark';
17→}
18→
19→function resolveTheme(preference: ThemePreference): ResolvedTheme {
20→  return preference === 'system' ? getSystemTheme() : preference;
21→}
22→
23→function applyTheme(theme: ResolvedTheme) {
24→  document.documentElement.setAttribute('data-theme', theme);
25→}
26→
27→export function useTheme() {
28→  const [preference, setPreference] = useState<ThemePreference>('dark');
29→  const [resolved, setResolved] = useState<ResolvedTheme>(() =>
30→    resolveTheme('dark'));
31→
32→  useEffect(() => {
33→    let cancelled = false;
34→    settingsDb
35→      .get(DB_KEY)
36→      .then(raw => {
37→        if (cancelled) return;
38→        const pref = isThemePreference(raw) ? raw : 'dark';
39→        setPreference(pref);
40→        const r = resolveTheme(pref);
41→        setResolved(r);
42→        applyTheme(r);
43→      })
44→      .catch(console.error);
45→    return () => {
46→      cancelled = true;
47→    };
48→  }, []);
49→
50→  useEffect(() => {
51→    const r = resolveTheme(preference);
52→    setResolved(r);
53→    applyTheme(r);
54→  }, [preference]);
55→
56→  useEffect(() => {
57→    if (preference !== 'system') return;
58→
59→    const mql = window.matchMedia('(prefers-color-scheme: light)');
60→    const handler = () => {
61→      const r = resolveTheme('system');
62→      setResolved(r);
63→      applyTheme(r);
64→    };
65→    mql.addEventListener('change', handler);
66→    return () => mql.removeEventListener('change', handler);
67→  }, [preference]);
68→
69→  const setTheme = useCallback((value: ThemePreference) => {
70→    setPreference(value);
71→    settingsDb.set(DB_KEY, value).catch(console.error);
72→  }, []);
73→
74→  return {
75→    preference,
76→    resolved,
77→    setTheme,
78→  };
79→}
