  1→import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
  2→import type { EmojiCategory, EmojiEntry } from '../../data/emoji_data';
  3→import {
  4→  EMOJI_CATEGORIES,
  5→  EMOJI_CATEGORY_LABELS,
  6→  EMOJI_CATEGORY_ORDER,
  7→  MOCK_EMOJIS,
  8→} from '../../data/emoji_data';
  9→import { useHUD } from '../../hooks/use_hud';
 10→import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
 11→import { useNavigation } from '../../hooks/use_navigation';
 12→import { settingsDb } from '../../utils/database';
 13→import { fuzzyMatch } from '../../utils/fuzzy_search';
 14→import { ActionPanel } from '../action_panel/action_panel';
 15→import { createCopyAction, performCopy } from '../action_panel/actions';
 16→import type { DropdownSection } from '../action_panel/actions_dropdown';
 17→import { EmptyState } from '../empty_state/empty_state';
 18→import { HUDContainer } from '../hud/hud_container';
 19→import { Kbd } from '../kbd/kbd';
 20→import { SearchBar } from '../search_bar/search_bar';
 21→import type { SearchDropdownSection } from '../search_bar/search_dropdown';
 22→import { SearchDropdown } from '../search_bar/search_dropdown';
 23→import './emoji_picker_view.scss';
 24→
 25→const COLUMNS = 6;
 26→const DB_KEY = 'emoji-recent';
 27→const MAX_RECENT = 12;
 28→
 29→function SearchEmptyIcon() {
 30→  return (
 31→    <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
 32→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
 33→      <line
 34→        x1="30"
 35→        y1="30"
 36→        x2="42"
 37→        y2="42"
 38→        stroke="currentColor"
 39→        strokeWidth="3"
 40→        strokeLinecap="round"
 41→      />
 42→    </svg>
 43→  );
 44→}
 45→
 46→function parseRecentEmojis(raw: string | null): string[] {
 47→  if (!raw) return [];
 48→  try {
 49→    const parsed: unknown = JSON.parse(raw);
 50→    if (Array.isArray(parsed) && parsed.every(v => typeof v === 'string')) {
 51→      return parsed as string[];
 52→    }
 53→  } catch {
 54→    // invalid
 55→  }
 56→  return [];
 57→}
 58→
 59→interface EmojiSection {
 60→  title: string;
 61→  emojis: EmojiEntry[];
 62→}
 63→
 64→const FILTER_SECTIONS: SearchDropdownSection[] = [
 65→  {
 66→    options: [
 67→      {
 68→        label: 'All',
 69→        value: 'all',
 70→      },
 71→    ],
 72→  },
 73→  {
 74→    title: 'Category',
 75→    options: EMOJI_CATEGORIES.map(c => ({
 76→      label: c.label,
 77→      value: c.value,
 78→    })),
 79→  },
 80→];
 81→
 82→export function EmojiPickerView() {
 83→  const nav = useNavigation();
 84→  const [query, setQuery] = useState('');
 85→  const [filterValue, setFilterValue] = useState('all');
 86→  const [activeIndex, setActiveIndex] = useState(0);
 87→  const [actionsOpen, setActionsOpen] = useState(false);
 88→  const [recentChars, setRecentChars] = useState<string[]>([]);
 89→
 90→  useEffect(() => {
 91→    let cancelled = false;
 92→    settingsDb
 93→      .get(DB_KEY)
 94→      .then(raw => {
 95→        if (!cancelled) setRecentChars(parseRecentEmojis(raw));
 96→      })
 97→      .catch(console.error);
 98→    return () => {
 99→      cancelled = true;
100→    };
101→  }, []);
102→  const { items: hudItems, show: showHUD } = useHUD();
103→  const containerRef = useRef<HTMLDivElement>(null);
104→
105→  const emojiLookup = useMemo(() => {
106→    const map = new Map<string, EmojiEntry>();
107→    for (const e of MOCK_EMOJIS) {
108→      map.set(e.char, e);
109→    }
110→    return map;
111→  }, []);
112→
113→  const recentEmojis = useMemo(
114→    () =>
115→      recentChars
116→        .map(char => emojiLookup.get(char))
117→        .filter((e): e is EmojiEntry => e !== undefined),
118→    [
119→      recentChars,
120→      emojiLookup,
121→    ],
122→  );
123→
124→  const filtered = useMemo(() => {
125→    let emojis = MOCK_EMOJIS;
126→    if (filterValue !== 'all') {
127→      emojis = emojis.filter(e => e.category === filterValue);
128→    }
129→    if (query) {
130→      emojis = emojis.filter(
131→        e =>
132→          fuzzyMatch(query, e.name) ||
133→          e.keywords.some(k => fuzzyMatch(query, k)) ||
134→          e.char === query,
135→      );
136→    }
137→    return emojis;
138→  }, [
139→    query,
140→    filterValue,
141→  ]);
142→
143→  const sections = useMemo(() => {
144→    const result: EmojiSection[] = [];
145→
146→    if (!query && filterValue === 'all' && recentEmojis.length > 0) {
147→      result.push({
148→        title: 'Recently Used',
149→        emojis: recentEmojis,
150→      });
151→    }
152→
153→    const grouped = new Map<EmojiCategory, EmojiEntry[]>();
154→    for (const emoji of filtered) {
155→      const existing = grouped.get(emoji.category);
156→      if (existing) {
157→        existing.push(emoji);
158→      } else {
159→        grouped.set(emoji.category, [emoji]);
160→      }
161→    }
162→
163→    for (const cat of EMOJI_CATEGORY_ORDER) {
164→      const items = grouped.get(cat);
165→      if (items && items.length > 0) {
166→        result.push({
167→          title: EMOJI_CATEGORY_LABELS[cat],
168→          emojis: items,
169→        });
170→      }
171→    }
172→
173→    return result;
174→  }, [
175→    filtered,
176→    query,
177→    filterValue,
178→    recentEmojis,
179→  ]);
180→
181→  const flatEmojis = useMemo(() => sections.flatMap(s => s.emojis), [sections]);
182→  const totalCount = flatEmojis.length;
183→
184→  useEffect(() => {
185→    if (totalCount === 0) {
186→      setActiveIndex(0);
187→    } else if (activeIndex >= totalCount) {
188→      setActiveIndex(totalCount - 1);
189→    }
190→  }, [
191→    totalCount,
192→    activeIndex,
193→  ]);
194→
195→  useEffect(() => {
196→    const container = containerRef.current;
197→    if (!container) return;
198→    const el = container.querySelector<HTMLElement>(
199→      `[data-emoji-index="${activeIndex}"]`,
200→    );
201→    el?.scrollIntoView({ block: 'nearest' });
202→  }, [activeIndex]);
203→
204→  const selectedEmoji = flatEmojis[activeIndex];
205→
206→  const addToRecent = useCallback((char: string) => {
207→    setRecentChars(prev => {
208→      const next = [
209→        char,
210→        ...prev.filter(c => c !== char),
211→      ].slice(0, MAX_RECENT);
212→      settingsDb.set(DB_KEY, JSON.stringify(next)).catch(console.error);
213→      return next;
214→    });
215→  }, []);
216→
217→  const handleCopyEmoji = useCallback(
218→    (emoji?: EmojiEntry) => {
219→      const target = emoji ?? selectedEmoji;
220→      if (!target) return;
221→      setActionsOpen(false);
222→      performCopy(target.char, showHUD, {
223→        hudTitle: `Copied ${target.char}`,
224→        onCopy: () => addToRecent(target.char),
225→      });
226→    },
227→    [
228→      selectedEmoji,
229→      showHUD,
230→      addToRecent,
231→    ],
232→  );
233→
234→  const handleQueryChange = useCallback((value: string) => {
235→    setQuery(value);
236→    setActiveIndex(0);
237→    setActionsOpen(false);
238→  }, []);
239→
240→  const handleFilterChange = useCallback((value: string) => {
241→    setFilterValue(value);
242→    setActiveIndex(0);
243→  }, []);
244→
245→  const toggleActions = useCallback(() => {
246→    setActionsOpen(prev => !prev);
247→  }, []);
248→
249→  const closeActions = useCallback(() => {
250→    setActionsOpen(false);
251→  }, []);
252→
253→  useKeyboardShortcut(
254→    {
255→      key: 'k',
256→      meta: true,
257→    },
258→    toggleActions,
259→  );
260→  useKeyboardShortcut(
261→    {
262→      key: 'c',
263→      meta: true,
264→    },
265→    () => handleCopyEmoji(),
266→  );
267→
268→  useEffect(() => {
269→    function handleKeyDown(e: KeyboardEvent) {
270→      if (totalCount === 0) return;
271→      if (actionsOpen) return;
272→      if (e.metaKey || e.ctrlKey || e.altKey) return;
273→
274→      const isTextInput =
275→        e.target instanceof HTMLInputElement ||
276→        e.target instanceof HTMLTextAreaElement;
277→
278→      switch (e.key) {
279→        case 'ArrowRight': {
280→          if (isTextInput) return;
281→          e.preventDefault();
282→          setActiveIndex(prev => (prev + 1 < totalCount ? prev + 1 : 0));
283→          break;
284→        }
285→        case 'ArrowLeft': {
286→          if (isTextInput) return;
287→          e.preventDefault();
288→          setActiveIndex(prev => (prev - 1 >= 0 ? prev - 1 : totalCount - 1));
289→          break;
290→        }
291→        case 'ArrowDown': {
292→          e.preventDefault();
293→          setActiveIndex(prev => {
294→            const sectionInfo = getSectionInfo(prev);
295→            if (!sectionInfo) return prev;
296→            const { sectionStart, sectionLength } = sectionInfo;
297→            const posInSection = prev - sectionStart;
298→            const row = Math.floor(posInSection / COLUMNS);
299→            const col = posInSection % COLUMNS;
300→            const sectionRows = Math.ceil(sectionLength / COLUMNS);
301→
302→            if (row + 1 < sectionRows) {
303→              const nextIdx = sectionStart + (row + 1) * COLUMNS + col;
304→              return nextIdx < sectionStart + sectionLength
305→                ? nextIdx
306→                : sectionStart + sectionLength - 1;
307→            }
308→
309→            const nextSectionStart = sectionStart + sectionLength;
310→            if (nextSectionStart < totalCount) {
311→              const nextInfo = getSectionInfo(nextSectionStart);
312→              if (!nextInfo) return prev;
313→              const targetIdx = nextSectionStart + col;
314→              return targetIdx < nextSectionStart + nextInfo.sectionLength
315→                ? targetIdx
316→                : nextSectionStart + nextInfo.sectionLength - 1;
317→            }
318→
319→            return prev;
320→          });
321→          break;
322→        }
323→        case 'ArrowUp': {
324→          e.preventDefault();
325→          setActiveIndex(prev => {
326→            const sectionInfo = getSectionInfo(prev);
327→            if (!sectionInfo) return prev;
328→            const { sectionStart } = sectionInfo;
329→            const posInSection = prev - sectionStart;
330→            const row = Math.floor(posInSection / COLUMNS);
331→            const col = posInSection % COLUMNS;
332→
333→            if (row > 0) {
334→              return sectionStart + (row - 1) * COLUMNS + col;
335→            }
336→
337→            if (sectionStart > 0) {
338→              const prevSectionEnd = sectionStart - 1;
339→              const prevInfo = getSectionInfo(prevSectionEnd);
340→              if (!prevInfo) return prev;
341→              const prevSectionRows = Math.ceil(
342→                prevInfo.sectionLength / COLUMNS,
343→              );
344→              const lastRowStart =
345→                prevInfo.sectionStart + (prevSectionRows - 1) * COLUMNS;
346→              const targetIdx = lastRowStart + col;
347→              return targetIdx < prevInfo.sectionStart + prevInfo.sectionLength
348→                ? targetIdx
349→                : prevInfo.sectionStart + prevInfo.sectionLength - 1;
350→            }
351→
352→            return prev;
353→          });
354→          break;
355→        }
356→        case 'Enter': {
357→          e.preventDefault();
358→          handleCopyEmoji();
359→          break;
360→        }
361→      }
362→    }
363→
364→    window.addEventListener('keydown', handleKeyDown);
365→    return () => window.removeEventListener('keydown', handleKeyDown);
366→  }, [
367→    totalCount,
368→    actionsOpen,
369→    handleCopyEmoji,
370→    sections,
371→  ]);
372→
373→  const sectionBoundaries = useMemo(() => {
374→    const boundaries: {
375→      start: number;
376→      length: number;
377→    }[] = [];
378→    let offset = 0;
379→    for (const section of sections) {
380→      boundaries.push({
381→        start: offset,
382→        length: section.emojis.length,
383→      });
384→      offset += section.emojis.length;
385→    }
386→    return boundaries;
387→  }, [sections]);
388→
389→  function getSectionInfo(index: number) {
390→    for (const b of sectionBoundaries) {
391→      if (index >= b.start && index < b.start + b.length) {
392→        return {
393→          sectionStart: b.start,
394→          sectionLength: b.length,
395→        };
396→      }
397→    }
398→    return null;
399→  }
400→
401→  const dropdownSections: DropdownSection[] = useMemo(
402→    () => [
403→      {
404→        title: 'Actions',
405→        actions: [
406→          createCopyAction(
407→            {
408→              content: selectedEmoji?.char ?? '',
409→              title: 'Copy Emoji',
410→              shortcut: <Kbd keys={['↵']} />,
411→              hudTitle: selectedEmoji
412→                ? `Copied ${selectedEmoji.char}`
413→                : 'Copied',
414→              onCopy: () => {
415→                if (selectedEmoji) addToRecent(selectedEmoji.char);
416→              },
417→            },
418→            showHUD,
419→          ),
420→          createCopyAction(
421→            {
422→              content: selectedEmoji?.char ?? '',
423→              title: 'Copy to Clipboard',
424→              shortcut: (
425→                <Kbd
426→                  keys={[
427→                    '⌘',
428→                    'C',
429→                  ]}
430→                />
431→              ),
432→              hudTitle: selectedEmoji
433→                ? `Copied ${selectedEmoji.char}`
434→                : 'Copied',
435→              onCopy: () => {
436→                if (selectedEmoji) addToRecent(selectedEmoji.char);
437→              },
438→            },
439→            showHUD,
440→          ),
441→        ],
442→      },
443→    ],
444→    [
445→      selectedEmoji,
446→      showHUD,
447→      addToRecent,
448→    ],
449→  );
450→
451→  const handleGridMouseOver = useCallback((
452→    e: React.MouseEvent<HTMLDivElement>,
453→  ) => {
454→    const target = (e.target as HTMLElement).closest<HTMLElement>(
455→      '[data-emoji-index]',
456→    );
457→    if (!target) return;
458→    const idx = Number(target.dataset.emojiIndex);
459→    if (!Number.isNaN(idx)) {
460→      setActiveIndex(idx);
461→    }
462→  }, []);
463→
464→  const activeDescendantId =
465→    totalCount > 0 ? `emoji-item-${activeIndex}` : undefined;
466→
467→  return (
468→    <>
469→      <SearchBar
470→        value={query}
471→        onChange={handleQueryChange}
472→        placeholder="Search Emoji..."
473→        activeDescendantId={activeDescendantId}
474→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
475→        dropdown={
476→          <SearchDropdown
477→            sections={FILTER_SECTIONS}
478→            value={filterValue}
479→            onChange={handleFilterChange}
480→          />
481→        }
482→      />
483→      <div className="command-palette__body">
484→        <div className="command-palette__list-container">
485→          {totalCount === 0 ? (
486→            <EmptyState
487→              icon={<SearchEmptyIcon />}
488→              title="No Emoji Found"
489→              description={
490→                query
491→                  ? 'Try a different search term'
492→                  : 'No emojis in this category'
493→              }
494→            />
495→          ) : (
496→            <div
497→              ref={containerRef}
498→              className="emoji-picker"
499→              role="listbox"
500→              id="emoji-grid"
501→              aria-label="Emoji list"
502→              aria-activedescendant={activeDescendantId}
503→              onMouseOver={handleGridMouseOver}
504→            >
505→              {(() => {
506→                let globalIndex = 0;
507→                return sections.map(section => (
508→                  <div key={section.title} className="emoji-picker__section">
509→                    <div className="emoji-picker__section-header">
510→                      {section.title}
511→                    </div>
512→                    <div className="emoji-picker__grid">
513→                      {section.emojis.map(emoji => {
514→                        const idx = globalIndex++;
515→                        const isActive = idx === activeIndex;
516→                        return (
517→                          <div
518→                            key={`${section.title}-${emoji.char}`}
519→                            id={`emoji-item-${idx}`}
520→                            className={`emoji-picker__cell${isActive ? ' emoji-picker__cell--active' : ''}`}
521→                            role="option"
522→                            aria-selected={isActive}
523→                            aria-label={emoji.name}
524→                            data-emoji-index={idx}
525→                            onClick={() => {
526→                              setActiveIndex(idx);
527→                              handleCopyEmoji(emoji);
528→                            }}
529→                          >
