 50→const DEFAULT_SETTINGS: GeneralSettings = {
 51→  appearance: 'dark',
 52→  windowPosition: 'top-third',
 53→  windowWidth: 'medium',
 54→  showRecentApps: true,
 55→  showDock: true,
 56→  fontSize: 'default',
 57→};
 58→
 59→function isGeneralSettings(value: unknown): value is GeneralSettings {
 60→  if (!isRecord(value)) return false;
 61→  return (
 62→    typeof value.appearance === 'string' &&
 63→    typeof value.windowWidth === 'string' &&
 64→    typeof value.showRecentApps === 'boolean' &&
 65→    typeof value.showDock === 'boolean' &&
 66→    typeof value.fontSize === 'string' &&
 67→    (value.windowPosition === undefined ||
 68→      typeof value.windowPosition === 'string')
 69→  );
 70→}
 71→
 72→function isBooleanRecord(value: unknown): value is Record<string, boolean> {
 73→  if (!isRecord(value)) return false;
 74→  return Object.values(value).every(v => typeof v === 'boolean');
 75→}
 76→
 77→function parseSettings(raw: string | null): GeneralSettings | null {
 78→  if (!raw) return null;
 79→  try {
 80→    const parsed: unknown = JSON.parse(raw);
 81→    return isGeneralSettings(parsed) ? parsed : null;
 82→  } catch {
 83→    return null;
 84→  }
 85→}
 86→
 87→function parseExtensionStates(
 88→  raw: string | null,
 89→): Record<string, boolean> | null {
 90→  if (!raw) return null;
 91→  try {
 92→    const parsed: unknown = JSON.parse(raw);
 93→    return isBooleanRecord(parsed) ? parsed : null;
 94→  } catch {
 95→    return null;
 96→  }
 97→}
