428→function ExtensionsTab({
429→  extensions,
430→  onToggle,
431→  query,
432→}: {
433→  extensions: ExtensionEntry[];
434→  onToggle: (id: string) => void;
435→  query: string;
436→}) {
437→  const filtered = useMemo(() => {
438→    if (!query) return extensions;
439→    const lower = query.toLowerCase();
440→    return extensions.filter(
441→      ext =>
442→        ext.name.toLowerCase().includes(lower) ||
443→        ext.description.toLowerCase().includes(lower) ||
444→        ext.author.toLowerCase().includes(lower),
445→    );
446→  }, [
447→    extensions,
448→    query,
449→  ]);
450→
451→  const raycastExts = filtered.filter(ext => ext.author === 'Raycast');
452→  const communityExts = filtered.filter(ext => ext.author !== 'Raycast');
453→
454→  return (
455→    <div className="settings-view__extensions">
456→      {filtered.length === 0 ? (
457→        <EmptyState
458→          icon={<SearchEmptyIcon />}
459→          title="No Extensions Found"
