124→function buildUpdateQuery(
125→  table: string,
126→  updates: Record<string, unknown>,
127→  allowedColumns: Set<string>,
128→  id: string
129→): {
130→  sql: string;
131→  values: unknown[];
132→} | null {
133→  const fields: string[] = [];
134→  const values: unknown[] = [];
135→  let idx = 1;
136→
137→  for (const [key, value] of Object.entries(updates)) {
138→    if (!allowedColumns.has(key)) continue;
139→    fields.push(`${key} = $${idx}`);
140→    values.push(value);
141→    idx++;
142→  }
143→
144→  if (fields.length === 0) return null;
145→  values.push(id);
146→  return {
147→    sql: `UPDATE ${table} SET ${fields.join(', ')} WHERE id = $${idx}`,
148→    values,
149→  };
150→}
